const sd = $getWorkflowStaticData('global');

// ---- init state ----
if (!sd.history) sd.history = [];
if (!sd.rules) sd.rules = "Genel: Sağlıklı ev yemeği, dengeli beslenme. Bir hafta içinde farklı protein kaynakları (tavuk/balık/kırmızı et/bakliyat/vejetaryen) dengeli dağılsın. Kızartma minimum.";
if (!sd.banned) sd.banned = [];
if (!sd.pending) sd.pending = {};
if (!sd.favorites) sd.favorites = [
  'Mercimek çorbası',
  'Tavuk sote',
  'Zeytinyağlı taze fasulye',
  'Nohut yemeği',
  'Fırında somon',
  'Sebzeli bulgur pilavı',
  'Kıymalı kabak yemeği',
  'Mantı'
];
if (!sd.weekPlan) sd.weekPlan = null;

// stale lock cleanup
if (sd.ollamaBusy && sd.ollamaBusySince && (Date.now() - sd.ollamaBusySince) > 180000) {
  sd.ollamaBusy = false;
  sd.ollamaBusySince = null;
}

// pending cleanup (10 min)
const now = Date.now();
Object.keys(sd.pending || {}).forEach(cid => {
  if (sd.pending[cid] && sd.pending[cid].since && (now - sd.pending[cid].since) > 600000) {
    delete sd.pending[cid];
  }
});

// ---- normalize incoming update from Telegram Trigger ----
const u = $json;

if (u.callback_query) {
  return [{
    json: {
      kind: 'callback',
      chatId: String(u.callback_query.message.chat.id),
      text: '',
      callbackData: u.callback_query.data || '',
      callbackQueryId: u.callback_query.id || ''
    }
  }];
}

if (u.message) {
  return [{
    json: {
      kind: 'message',
      chatId: String(u.message.chat.id),
      text: (typeof u.message.text === 'string') ? u.message.text : '',
      callbackData: '',
      callbackQueryId: ''
    }
  }];
}

return [{ json: { kind: 'unknown', chatId: '', text: '', callbackData: '', callbackQueryId: '' } }];

const sd = $getWorkflowStaticData('global');
const chatId = String($json.chatId);

if (chatId !== "-4929983051") return [{ json: { action: 'ignore' } }];

const data = $json.callbackData || '';
const m = data.match(/^mode:(1|2|3)$/);
if (!m) return [{ json: { action: 'noop' } }];

const mode = m[1];
if (mode === '1') {
  sd.pending[chatId] = { type: 'ingredients', since: Date.now() };
  return [{ json: { action: 'ask_ingredients', chatId } }];
}
return [{ json: { action: 'generate', chatId, mode } }];

const sd = $getWorkflowStaticData('global');
const chatId = String($json.chatId);
const rawText = $json.text ?? '';
const text = (typeof rawText === 'string' ? rawText : String(rawText ?? '')).trim();
if (!text) return [{ json: { action: 'noop' } }];

if (chatId !== "-4929983051") return [{ json: { action: 'ignore' } }];

// FIX: Süresi dolmuş pending'leri temizle (10 dakika)
const now = Date.now();
Object.keys(sd.pending || {}).forEach(cid => {
  if (sd.pending[cid] && sd.pending[cid].since && (now - sd.pending[cid].since) > 600000) {
    delete sd.pending[cid];
  }
});

// /help komutu (YENİ)
if (text.startsWith('/help') || text === '?') {
  const helpMsg = `🤖 <b>Akşam Yemeği Botu - Komutlar</b>\n\n` +
    `<b>🍽️ Öneri:</b>\n` +
    `• <code>2</code> veya <code>3</code> — Direkt öneri (2=normal, 3=hafif)\n` +
    `• <code>1</code> — Evdeki malzemelere göre öneri\n\n` +
    `<b>📅 Haftalık Plan:</b>\n` +
    `• /plan — Yeni 7 günlük plan oluştur\n` +
    `• /plan goster — Mevcut planı göster\n` +
    `• /plan sil — Planı sıfırla\n` +
    `• /plan_json — Planı JSON olarak göster\n\n` +
    `<b>⭐ Favoriler:</b>\n` +
    `• /favoriler — Favori listesi\n• /tarif &lt;yemek&gt; — İstediğin yemeğin tarifini getir\n` +
    `• /fav_ekle &lt;yemek&gt; — Favoriye ekle\n` +
    `• /fav_sil &lt;yemek&gt; — Favoriden sil\n\n` +
    `<b>⚙️ Yönetim:</b>\n` +
    `• /history — Son 7 öneri\n` +
    `• /rules — Mevcut kuralları gör\n` +
    `• /rules &lt;yeni kurallar&gt; — Kuralları güncelle\n` +
    `• /ban &lt;yemek&gt; — Yasakla\n` +
    `• /unban &lt;yemek&gt; — Yasağı kaldır\n` +
    `• /reset — Tüm hafızayı sıfırla`;
  return [{ json: { action: 'reply_html', chatId, message: helpMsg } }];
}

if (text.startsWith('/reset')) {
  sd.history = [];
  sd.banned = [];
  sd.rules = "Genel: Sağlıklı ev yemeği, dengeli beslenme. Bir hafta içinde farklı protein kaynakları (tavuk/balık/kırmızı et/bakliyat/vejetaryen) dengeli dağılsın. Kızartma minimum.";
  sd.pending = {};
  sd.ollamaBusy = false;
  sd.ollamaBusySince = null;
  return [{ json: { action: 'reply', chatId, message: '✅ Hafıza sıfırlandı (history/rules/ban/pending/lock).' } }];
}

if (text.startsWith('/history')) {
  const h = (sd.history || []).slice(-7)
    .map((x,i)=>`${i+1}) ${x.date} • ${x.title} (${x.proteinTag||'protein?'})`)
    .join('\n');
  return [{ json: { action: 'reply', chatId, message: h ? `📌 Son öneriler:\n${h}` : 'Henüz geçmiş yok.' } }];
}

if (text.startsWith('/rules')) {
  const newRules = text.replace('/rules','').trim();
  if (!newRules) {
    return [{ json: { action: 'reply', chatId, message: `Mevcut kurallar:\n${sd.rules}\n\nGüncellemek için: /rules <yeni kurallar>` } }];
  }
  sd.rules = newRules;
  return [{ json: { action: 'reply', chatId, message: '✅ Kurallar güncellendi.' } }];
}

if (text.startsWith('/ban')) {
  const item = text.replace('/ban','').trim().toLowerCase();
  if (!item) return [{ json: { action: 'reply', chatId, message: 'Kullanım: /ban pizza' } }];
  if (!sd.banned.includes(item)) sd.banned.push(item);
  return [{ json: { action: 'reply', chatId, message: `⛔️ Yasaklara eklendi: ${item}` } }];
}

if (text.startsWith('/unban')) {
  const item = text.replace('/unban','').trim().toLowerCase();
  sd.banned = (sd.banned || []).filter(x => x !== item);
  return [{ json: { action: 'reply', chatId, message: `✅ Yasaktan çıkarıldı: ${item}` } }];
}

if (text.startsWith('/fav_ekle') || text.startsWith('/favori_ekle')) {
  const item = text.replace('/fav_ekle','').replace('/favori_ekle','').trim();
  if (!item) return [{ json: { action: 'reply', chatId, message: 'Kullanım: /fav_ekle <yemek ismi>' } }];
  const norm = item.toLowerCase();
  const exists = (sd.favorites||[]).some(x => String(x).toLowerCase() === norm);
  if (!exists) sd.favorites.push(item);
  return [{ json: { action: 'reply', chatId, message: exists ? 'ℹ️ Zaten favorilerde.' : `✅ Favorilere eklendi: ${item}` } }];
}

if (text.startsWith('/fav_sil') || text.startsWith('/favori_sil')) {
  const item = text.replace('/fav_sil','').replace('/favori_sil','').trim().toLowerCase();
  if (!item) return [{ json: { action: 'reply', chatId, message: 'Kullanım: /fav_sil <yemek ismi>' } }];
  const before = (sd.favorites||[]).length;
  sd.favorites = (sd.favorites||[]).filter(x => String(x).toLowerCase() !== item);
  const after = sd.favorites.length;
  return [{ json: { action: 'reply', chatId, message: before === after ? 'ℹ️ Bulunamadı.' : `✅ Favorilerden silindi: ${item}` } }];
}

if (text.startsWith('/fav_liste') || text.startsWith('/favoriler')) {
  const list = (sd.favorites||[]);
  const msg = list.length ? ('⭐ Favoriler:\n' + list.map((x,i)=>`${i+1}) ${x}`).join('\n')) : 'Favori listesi boş.';
  return [{ json: { action: 'reply', chatId, message: msg } }];
}

if (text.startsWith('/tarif')) {
  const dish = text.replace('/tarif','').trim();
  if (!dish) return [{ json: { action: 'reply', chatId, message: 'Kullanım: /tarif <yemek adı>\nÖrnek: /tarif karnıyarık' } }];
  return [{ json: { action: 'generate', chatId, mode: '2', forcedDish: dish } }];
}

if (text.startsWith('/plan_json')) {
  if (!sd.weekPlan) return [{ json: { action: 'reply', chatId, message: 'Henüz plan yok. /plan ile oluştur.' } }];
  return [{ json: { action: 'reply', chatId, message: JSON.stringify(sd.weekPlan.plan, null, 2) } }];
}

if (text.startsWith('/plan')) {
  const arg = text.replace('/plan','').trim().toLowerCase();
  if (arg === 'sil' || arg === 'reset') {
    sd.weekPlan = null;
    return [{ json: { action: 'reply', chatId, message: '✅ Haftalık plan sıfırlandı.' } }];
  }
  if (arg === 'goster' || arg === 'show') {
    if (!sd.weekPlan) return [{ json: { action: 'reply', chatId, message: 'Henüz plan yok. Yeni plan için /plan yaz.' } }];
    const lines = sd.weekPlan.plan.map((d,i)=>`${i+1}) ${d.date} • ${d.title} (${d.proteinTag})`).join('\n');
    return [{ json: { action: 'reply', chatId, message: `📅 Mevcut 7 günlük plan:\n${lines}` } }];
  }
  return [{ json: { action: 'plan', chatId } }];
}

// pending kontrolü
const pend = sd.pending[chatId];

// Plan seçimi bekleniyor
if (pend && pend.type === 'plan_selection') {
  const nums = text.split(/[\s,]+/).map(n => parseInt(n)).filter(n => !isNaN(n));
  if (nums.length < 7) {
    return [{ json: { action: 'reply', chatId, message: '⚠️ Lütfen tam olarak 7 yemek numarası yaz.\nÖrnek: 1 3 5 7 9 11 13' } }];
  }
  const suggestions = (sd.pendingPlanSuggestions || {}).suggestions || [];
  const start = (sd.pendingPlanSuggestions || {}).start || '';
  const selected = nums.slice(0, 7).map((n, i) => {
    const found = suggestions.find(s => s.id === n);
    if (!found) return null;
    const dt = new Date(new Date(start).getTime() + i * 86400000);
    const yyyy = dt.getFullYear();
    const mm = String(dt.getMonth() + 1).padStart(2, '0');
    const dd = String(dt.getDate()).padStart(2, '0');
    return { date: yyyy + '-' + mm + '-' + dd, title: found.title, proteinTag: found.proteinTag, prepMinutes: 30, lightLevel: 'orta' };
  }).filter(Boolean);
  if (selected.length < 7) {
    return [{ json: { action: 'reply', chatId, message: '⚠️ Bazı numaralar listede yok. Tekrar dene.' } }];
  }
  delete sd.pending[chatId];
  delete sd.pendingPlanSuggestions;
  sd.weekPlan = { generatedAt: Date.now(), startDate: start, plan: selected };

  function escHtml(str) {
    return String(str || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }
  const lines = selected.map((d, i) =>
    (i+1) + ') ' + escHtml(d.date) + ' • <b>' + escHtml(d.title) + '</b> (' + escHtml(d.proteinTag) + ')'
  ).join('\n');
  const msg = '📅 <b>7 Günlük Plan</b> (başlangıç ' + escHtml(start) + ')\n\n' + lines + '\n\nJSON görmek için: /plan_json\nFavoriler için: /favoriler';
  return [{ json: { action: 'reply_html', chatId, message: msg } }];
}

// Ingredients bekleniyor
if (pend && pend.type === 'ingredients') {
  delete sd.pending[chatId];
  return [{ json: { action: 'generate', chatId, mode: '1', ingredients: text } }];
}

if (['1','2','3'].includes(text)) {
  if (text === '1') {
    sd.pending[chatId] = { type: 'ingredients', since: Date.now() };
    return [{ json: { action: 'ask_ingredients', chatId } }];
  }
  return [{ json: { action: 'generate', chatId, mode: text } }];
}

return [{ json: { action: 'noop' } }];

