const sd = $getWorkflowStaticData('global');
const mode = String($json.mode);
const rawIng = $json.ingredients ?? '';
const ingredients = (typeof rawIng === 'string' ? rawIng : String(rawIng ?? '')).trim();
const forcedDish = $json.forcedDish || null;

const now = new Date();
const yyyy = now.getFullYear();
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');
const today = yyyy + '-' + mm + '-' + dd;

const sevenDaysAgo = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 7);
const history = (sd.history || []).slice(-14);
const banned = (sd.banned || []);
const favorites = (sd.favorites || []);

const recentTitles = history
  .filter(h => h.date && new Date(h.date) >= sevenDaysAgo)
  .map(h => String(h.title || '').toLowerCase());

const candidateFavs = favorites.filter(f => !recentTitles.includes(String(f).toLowerCase()));

let modeDesc;
if (forcedDish) {
  modeDesc = 'Haftalik plandan tarif: ' + forcedDish;
} else if (mode === '1') {
  modeDesc = 'Evdeki malzemelere gore';
} else if (mode === '3') {
  modeDesc = 'Hafif';
} else {
  modeDesc = 'Direkt oner';
}

const favStr = candidateFavs.length ? candidateFavs.join(', ') : (favorites.length ? favorites.join(', ') : 'yok');
const banStr = banned.length ? banned.join(', ') : 'yok';
const histStr = history.length ? history.map(h => h.date + ':' + h.title).join(' | ') : 'yok';
const ingLine = mode === '1' ? ('EVDEKİ MALZEMELER: ' + ingredients) : '';
const forcedLine = forcedDish ? ('ZORUNLU YEMEK: Tarifi kesinlikle "' + forcedDish + '" olacak, baska yemek onerme.') : '';

const prompt = [
  'Sen profesyonel, pratik ve cozum odakli bir Turk mutfagi sefisin. Gorev: 3 kisilik aile icin dengeli ve hizli aksam yemegi oner.',
  '',
  'KURALLAR:',
  '- Her yemek hazirlik dahil en fazla 35 dakikada servis edilebilir olmali.',
  '- Haftalik protein dengesi: kirmizi et, beyaz et ve zeytinyagli/baklagil dengeli dagilsin.',
  '- Airfryer yoktur; tencere, tava, firin kullanilabilir.',
  '- Alisveris haftalik yapilir; evde bulunmasi muhtemel temel malzemelere oncelik ver.',
  '- Her tarifde MUTLAKA baharat kullan (kimyon, pul biber, karabiber, nane, kekik, sarimsak vb.). Baharatsiz tarif kabul edilmez.',
  '- Tarif basligi (title) sadece tek bir yemegi tanimlamali, "ve Pilav" veya "ve Salata" gibi ek yemek adlari ekleme.',
  '',
  'FAVORİLER (oncelik, son 7 gunde yapilmamis): ' + favStr,
  'YASAKLILAR: ' + banStr,
  'SON ONERİLER (son 14): ' + histStr,
  '',
  'MOD: ' + modeDesc,
  ingLine,
  forcedLine,
  '',
  'CIKTI KURALLARI:',
  '- Sadece asagidaki JSON semasina uygun gecerli JSON dondurun, baska hicbir sey yazma.',
  '- Tum Turkce karakterleri (s=ş, g=ğ, u=ü, o=ö, c=ç, i=ı) OLDUGU GIBI yaz, unicode escape kullanma.',
  '{',
  '  "title": "...",',
  '  "proteinTag": "tavuk|balik|kirmizi_et|bakliyat|vejetaryen|karisik",',
  '  "prepMinutes": 30,',
  '  "ingredients": ["3 kisilik olculerle yaz", "baharat miktarlarini da ekle"],',
  '  "steps": ["adim1", "adim2", "adim3", "adim4", "adim5", "adim6"],',
  '  "nutritionNote": "kisa ve dogru besin notu",',
  '  "lightLevel": "hafif|orta"',
  '}'
].join('\n');

return [{ json: { today, mode, prompt, forcedDish } }];

const sd = $getWorkflowStaticData('global');
// FIX: Busy lock — timestamp ile birlikte set et
if (sd.ollamaBusy) {
  return [{ json: { skip: true } }];
}
sd.ollamaBusy = true;
sd.ollamaBusySince = Date.now();
return [{ json: { skip: false } }];

const sd = $getWorkflowStaticData('global');
sd.ollamaBusy = false;
sd.ollamaBusySince = null;

const today = $node["Build prompt (Ollama)"].json.today;
const mode = $node["Build prompt (Ollama)"].json.mode;

let candidate = $json.response ?? $json.body?.response ?? '';
candidate = String(candidate);

// Unicode escape'leri decode et (\u015f gibi literal string olarak geldiyse)
// JSON.parse zaten handle eder, ama raw string olarak geldiyse:
try {
  candidate = candidate.replace(/\\u([0-9a-fA-F]{4})/g, (_, hex) =>
    String.fromCharCode(parseInt(hex, 16))
  );
} catch(e) {}

candidate = candidate
  .replace(/```json/gi, '```')
  .replace(/```/g, '')
  .trim();

function extractFirstJsonObject(str) {
  const start = str.indexOf('{');
  if (start === -1) return null;
  let depth = 0;
  let inString = false;
  let escape = false;
  for (let i = start; i < str.length; i++) {
    const ch = str[i];
    if (inString) {
      if (escape) { escape = false; }
      else if (ch === '\\') { escape = true; }
      else if (ch === '"') { inString = false; }
      continue;
    }
    if (ch === '"') { inString = true; continue; }
    if (ch === '{') depth++;
    if (ch === '}') depth--;
    if (depth === 0) return str.slice(start, i + 1);
  }
  return null;
}

const jsonText = extractFirstJsonObject(candidate);
if (!jsonText) {
  throw new Error('JSON objesi bulunamadı. İlk 400: ' + candidate.slice(0, 400));
}

let obj;
try {
  obj = JSON.parse(jsonText);
} catch (e) {
  throw new Error('JSON parse başarısız. İlk 400: ' + jsonText.slice(0, 400));
}

if (!sd.history) sd.history = [];
sd.history.push({ date: today, title: obj.title, proteinTag: obj.proteinTag, mode });
sd.history = sd.history.slice(-30);

return [{ json: { obj } }];

const sd = $getWorkflowStaticData('global');
sd.ollamaBusy = false;
sd.ollamaBusySince = null;
const errMsg = $json.error?.message || $json.message || 'Bilinmeyen hata';
return [{ json: { message: '⚠️ Bir sorun oluştu, lütfen tekrar dene.\n(' + errMsg.slice(0,100) + ')' } }];

const o = $json.obj;

function escHtml(str) {
  return String(str || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

const ing = (o.ingredients || []).map(x => '• ' + escHtml(x)).join('\n');
const steps = (o.steps || []).map((x, i) => (i + 1) + ') ' + escHtml(x)).join('\n');

const msg = '🍽️ <b>' + escHtml(o.title) + '</b>\n\n' +
  '🏷️ Protein: <b>' + escHtml(o.proteinTag) + '</b> | Hafiflik: <b>' + escHtml(o.lightLevel || 'orta') + '</b>\n' +
  '⏱️ Hazırlık: <b>' + escHtml(String(o.prepMinutes)) + ' dk</b>\n\n' +
  '🧺 <b>Malzemeler:</b>\n' + (ing || '• (liste yok)') + '\n\n' +
  '👩‍🍳 <b>Yapılış:</b>\n' + (steps || '(adım yok)') + '\n\n' +
  '🥗 <i>Beslenme notu:</i> ' + escHtml(o.nutritionNote || '');

return [{ json: { text: msg } }];

const sd = $getWorkflowStaticData('global');

const now = new Date();
const day = now.getDay();
const daysUntilMon = (day === 1) ? 0 : ((8 - day) % 7);
const startDate = new Date(now.getFullYear(), now.getMonth(), now.getDate() + daysUntilMon);
const yyyy = startDate.getFullYear();
const mm = String(startDate.getMonth()+1).padStart(2,'0');
const dd = String(startDate.getDate()).padStart(2,'0');
const start = yyyy + '-' + mm + '-' + dd;

if (sd.ollamaBusy) {
  return [{ json: { action: 'reply', chatId: $json.chatId, message: '⏳ Şu an başka bir istek işleniyor, lütfen biraz bekle.' } }];
}
sd.ollamaBusy = true;
sd.ollamaBusySince = Date.now();

const favorites = (sd.favorites || []);
const history = (sd.history || []).slice(-21);
const banned = (sd.banned || []);

const now2 = new Date();
const twentyOneDaysAgo = new Date(now2.getFullYear(), now2.getMonth(), now2.getDate() - 21);
const recentTitles = history
  .filter(h => h.date && new Date(h.date) >= twentyOneDaysAgo)
  .map(h => String(h.title || '').toLowerCase());
const candidateFavs = favorites.filter(f => !recentTitles.includes(String(f).toLowerCase()));

const favStr = candidateFavs.length ? candidateFavs.join(', ') : (favorites.length ? favorites.join(', ') : 'yok');
const banStr = banned.length ? banned.join(', ') : 'yok';
const histStr = history.length ? history.map(h => h.date + ':' + h.title).join(' | ') : 'yok';

const prompt = [
  'Sen bir Türk mutfağı şefisin. Görev: kullanıcıya seçim yapması için 14 yemek adı öner.',
  '',
  'KURALLAR:',
  '- Öneriler çeşitli olsun: tavuk, balık, kırmızı et, bakliyat, vejetaryen karışık dağılsın.',
  '- Favorilerden mümkün olduğunca çok öner (son 21 günde yapılmamış olanlar öncelikli).',
  '- Yasaklı yemekleri önerme.',
  '- Son 21 günde yapılan yemekleri tekrar önerme.',
  '- Her öneri tek bir yemek adı olsun, kısa ve net.',
  '',
  'FAVORİ ADAYLAR (öncelikli öner): ' + favStr,
  'YASAKLILAR: ' + banStr,
  'SON YAPILAN (son 21 gün): ' + histStr,
  '',
  'ÇIKTI: Sadece aşağıdaki JSON formatında 14 elemanlı dizi döndür, başka hiçbir şey yazma:',
  '[',
  '  {"id": 1, "title": "...", "proteinTag": "tavuk|balık|kırmızı_et|bakliyat|vejetaryen|karışık"},',
  '  {"id": 2, "title": "...", "proteinTag": "..."},',
  '  ...',
  '  {"id": 14, "title": "...", "proteinTag": "..."}',
  ']'
].join('\n');

return [{ json: { start, prompt, chatId: $json.chatId } }];

const sd = $getWorkflowStaticData('global');
sd.ollamaBusy = false;
sd.ollamaBusySince = null;

const start = $node['Build plan prompt (Ollama)'].json.start;
const chatId = $node['Build plan prompt (Ollama)'].json.chatId;

let candidate = $json.response ?? $json.body?.response ?? '';
candidate = String(candidate);

try {
  candidate = candidate.replace(/\\u([0-9a-fA-F]{4})/g, (_, hex) =>
    String.fromCharCode(parseInt(hex, 16))
  );
} catch(e) {}

candidate = candidate.replace(/```json/gi,'```').replace(/```/g,'').trim();

let suggestions;
try {
  suggestions = JSON.parse(candidate);
} catch (e) {
  const m = candidate.match(/\[[\s\S]*\]/);
  if (!m) throw new Error('Öneri JSON bulunamadı. İlk 400: ' + candidate.slice(0,400));
  suggestions = JSON.parse(m[0]);
}

if (!Array.isArray(suggestions) || suggestions.length < 7) {
  throw new Error('En az 7 öneri gelmeli. Gelen: ' + JSON.stringify(suggestions).slice(0,200));
}

// Öneri listesini state'e kaydet, seçim bekle
sd.pendingPlanSuggestions = { suggestions, start, since: Date.now() };
sd.pending[chatId] = { type: 'plan_selection', since: Date.now() };

function escHtml(str) {
  return String(str || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

const PROTEIN_EMOJI = {
  tavuk: '🍗',
  'balık': '🐟',
  'kırmızı_et': '🥩',
  bakliyat: '🫘',
  vejetaryen: '🥦',
  'karışık': '🍲'
};

const lines = suggestions.map(s => {
  const emoji = PROTEIN_EMOJI[s.proteinTag] || '🍽️';
  return emoji + ' ' + s.id + ') ' + escHtml(s.title);
}).join('\n');

const msg = '🍽️ <b>Bu haftaki menü için yemek seç!</b>\n\n' +
  lines + '\n\n' +
  '👇 <b>7 yemek seç</b> — numaraları boşlukla yaz:\n' +
  '<i>Örnek: 1 3 5 7 9 11 13</i>';

return [{ json: { message: msg } }];

const sd = $getWorkflowStaticData('global');
sd.ollamaBusy = false;
sd.ollamaBusySince = null;
const errMsg = $json.error?.message || $json.message || 'Bilinmeyen hata';
return [{ json: { message: '⚠️ Plan oluşturulurken sorun çıktı, tekrar dene.\n(' + errMsg.slice(0,100) + ')' } }];
